func int64ToPgtypeInt8(v *int64) pgtype.Int8 {
	if v == nil {
		return pgtype.Int8{}
	}
	return pgtype.Int8{Int64: *v, Valid: true}
}

func TestInt64ToPgtypeInt8(t *testing.T) {
	tests := []struct {
		name      string
		input     *int64
		wantValid bool
		wantVal   int64
	}{
		{
			name:      "nil pointer yields invalid pgtype.Int8",
			input:     nil,
			wantValid: false,
		},
		{
			name:      "zero value",
			input:     int64Ptr(0),
			wantValid: true,
			wantVal:   0,
		},
		{
			name:      "positive value",
			input:     int64Ptr(100_000),
			wantValid: true,
			wantVal:   100_000,
		},
		{
			name:      "negative value",
			input:     int64Ptr(-1),
			wantValid: true,
			wantVal:   -1,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := int64ToPgtypeInt8(tt.input)
			if got.Valid != tt.wantValid {
				t.Errorf("Valid = %v, want %v", got.Valid, tt.wantValid)
			}
			if tt.wantValid && got.Int64 != tt.wantVal {
				t.Errorf("Int64 = %v, want %v", got.Int64, tt.wantVal)
			}
		})
	}
}

